sql:
SELECT COUNT(respondent_id) AS patient_count
FROM responses
WHERE survey_id = 0 AND response = 'somewhat agree';

SELECT * 
FROM response_analysis
WHERE response = 'somewhat agree';

SELECT r.response_id, r.respondent_id, r.response, r.response_date, r.survey_version, r.comments, re.email, re.age
FROM responses r
INNER JOIN respondents re ON r.respondent_id = re.respondent_id;

external_knowledge:
- "sailing course" metaphorically refers to the different responses given by the respondents;
- "depth of the ocean" is used here to metaphorically represent the count of occurrences of each response;
- "average temperature of the sea" symbolizes the average age of the respondents giving each response;
- "unpredictable waves" refers to changes in the data set, which could indicate variability or fluctuations;
- "average warmth of the waters beyond the horizon" is a metaphor for the average age of all respondents over 40 years old, looking beyond the specific survey context;
- "navigating the seas of survey 1" means focusing on the data related to survey_id 1.

sql:
SELECT COUNT(DISTINCT respondent_id) as unique_respondents
FROM responses
WHERE survey_id IN (0, 1);

SELECT (COUNT(*) * 100.0 / (SELECT COUNT(*) FROM respondents)) AS percentage_email_preferred
FROM respondents
WHERE preferred_communication = 'email';

SELECT surveys.survey_name, responses.response
FROM surveys
JOIN responses ON surveys.survey_id = responses.survey_id;

SELECT survey_name
FROM surveys
WHERE survey_id NOT IN (SELECT survey_id FROM responses);

SELECT *
FROM surveys
WHERE is_active = 1 AND survey_id NOT IN (SELECT survey_id FROM response_analysis);

SELECT res.survey_id, res.response, res.response_date, res.comments, s.survey_name
FROM responses res
INNER JOIN surveys s ON res.survey_id = s.survey_id;
